// Job Filter
function jobFilter() {

    const role = document.getElementById("roleList").value;
    const location = document.getElementById("locationList").value;
    const company = document.getElementById("companyList").value;
    const sortJobs = jobs.filter(job => {
        return (
            (role === "" || job.role === role) &&
            (location === "" || job.location === location) &&
            (company === "" || job.company === company)
        );
    });
    jobCard(sortJobs)
}
// Add Jobs
function addJobs() {

}

// Delete Jobs
function jobDelete(jobs, id) {
    jobs = jobs.filter(job => job.id !== id);
    // console.log(jobs)
}

// =============== Lists ========================
function dropDownList(jobs) {
    var companyList = document.getElementById("companyList");
    var locationList = document.getElementById("locationList");
    var roleList = document.getElementById("roleList");
    // Push Types
    jobs.forEach(job => {
        locations.push(job.location)
        roles.push(job.role)
        companies.push(job.company)
    });
    // Company
    companies.forEach(company => {
        companyList.innerHTML += `
            <option value="${company}">${company}</option>
        `;
    });
    // Roles
    roles.forEach(role => {
        roleList.innerHTML += `
            <option value="${role}">${role}</option>
        `;
    });
    // Locations
    locations.forEach(location => {
        locationList.innerHTML += `
            <option value="${location}">${location}</option>
        `;
    });
}





